import{_ as a,o as t,c as n,ai as s}from"./chunks/framework.C4ntERNc.js";const m=JSON.parse('{"title":"Memory (MEM) Reference","description":"","frontmatter":{"title":"Memory (MEM) Reference","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/memory.md","filePath":"reference-manual/formal-reference/memory.md"}'),d={name:"reference-manual/formal-reference/memory.md"};function i(l,e,o,r,c,p){return t(),n("div",null,[...e[0]||(e[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/memory.md for this page in Markdown format</div><h1 id="memory-mem-reference" tabindex="-1">Memory (MEM) Reference <a class="header-anchor" href="#memory-mem-reference" aria-label="Permalink to “Memory (MEM) Reference”">​</a></h1><h2 id="memory-port-modes" tabindex="-1">Memory Port Modes <a class="header-anchor" href="#memory-port-modes" aria-label="Permalink to “Memory Port Modes”">​</a></h2><p>JZ-HDL MEM declarations express all common BSRAM operating modes through port type combinations.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Port Configuration</th><th style="text-align:left;">BSRAM Mode</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>OUT</code> only</td><td style="text-align:left;">Read Only Memory</td><td style="text-align:left;">Read-only, initialized at power-on</td></tr><tr><td style="text-align:left;"><code>INOUT</code> ×1</td><td style="text-align:left;">Single Port</td><td style="text-align:left;">One shared-address port for read and write</td></tr><tr><td style="text-align:left;"><code>IN</code> + <code>OUT</code></td><td style="text-align:left;">Semi-Dual Port</td><td style="text-align:left;">Separate write port and read port</td></tr><tr><td style="text-align:left;"><code>INOUT</code> ×2</td><td style="text-align:left;">Dual Port</td><td style="text-align:left;">Two independent read/write ports</td></tr></tbody></table><p><strong>Note:</strong> <code>INOUT</code> ports cannot be mixed with <code>IN</code> or <code>OUT</code> ports in the same MEM declaration.</p><h2 id="declaration" tabindex="-1">Declaration <a class="header-anchor" href="#declaration" aria-label="Permalink to “Declaration”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>MEM(type=[BLOCK|DISTRIBUTED]) {</span></span>
<span class="line"><span>  &lt;name&gt; [&lt;word_width&gt;] [&lt;depth&gt;] = &lt;init&gt; {</span></span>
<span class="line"><span>    OUT   &lt;port_id&gt; [ASYNC | SYNC];</span></span>
<span class="line"><span>    IN    &lt;port_id&gt;;</span></span>
<span class="line"><span>    IN    &lt;port_id&gt; { WRITE_MODE = &lt;mode&gt;; };</span></span>
<span class="line"><span>    INOUT &lt;port_id&gt;;</span></span>
<span class="line"><span>  };</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li><code>type</code> is optional. When omitted: depth &lt;= 16 infers DISTRIBUTED; depth &gt; 16 with all SYNC OUT ports infers BLOCK.</li><li>Address width is <code>clog2(depth)</code>. Minimum address width is 1 bit; a single-word memory (depth=1) uses a 1-bit address (the sole word lives at address <code>1&#39;b0</code>).</li><li>OUT ports are read ports; IN ports are write ports; INOUT ports are combined read/write.</li><li>At least one port (IN, OUT, or INOUT) is required.</li><li><code>INOUT</code> ports cannot be mixed with <code>IN</code> or <code>OUT</code> ports in the same MEM declaration.</li></ul><h2 id="port-types" tabindex="-1">Port types <a class="header-anchor" href="#port-types" aria-label="Permalink to “Port types”">​</a></h2><h3 id="out-async-asynchronous-read" tabindex="-1">OUT ASYNC (asynchronous read) <a class="header-anchor" href="#out-async-asynchronous-read" aria-label="Permalink to “OUT ASYNC (asynchronous read)”">​</a></h3><ul><li>Combinational address-to-data path.</li><li>Used in <code>ASYNCHRONOUS</code> blocks only.</li><li>Access: <code>mem.port[address]</code></li><li>Result width equals word_width.</li></ul><h3 id="out-sync-synchronous-read" tabindex="-1">OUT SYNC (synchronous read) <a class="header-anchor" href="#out-sync-synchronous-read" aria-label="Permalink to “OUT SYNC (synchronous read)”">​</a></h3><ul><li>Exposes two pseudo-fields: <code>.addr</code> and <code>.data</code>.</li><li><code>.addr</code> is assigned in <code>SYNCHRONOUS</code> blocks with <code>&lt;=</code>.</li><li><code>.data</code> is the read result, valid the cycle after <code>.addr</code> is sampled.</li><li><code>.data</code> is readable in any block (ASYNCHRONOUS or SYNCHRONOUS).</li><li><code>mem.port[addr]</code> indexing is illegal for SYNC ports (use <code>.addr</code>/<code>.data</code> instead).</li><li><code>.addr</code> may be assigned at most once per execution path.</li></ul><h3 id="in-synchronous-write" tabindex="-1">IN (synchronous write) <a class="header-anchor" href="#in-synchronous-write" aria-label="Permalink to “IN (synchronous write)”">​</a></h3><ul><li>Always synchronous; address and data sampled at clock edge.</li><li>Used only in <code>SYNCHRONOUS</code> blocks.</li><li>Access: <code>mem.port[address] &lt;= value;</code></li><li>Each IN port may be written at most once per synchronous execution path.</li></ul><h3 id="inout-read-write-port" tabindex="-1">INOUT (read/write port) <a class="header-anchor" href="#inout-read-write-port" aria-label="Permalink to “INOUT (read/write port)”">​</a></h3><ul><li>Combined read/write port with shared address.</li><li>Always synchronous (no <code>ASYNC</code>/<code>SYNC</code> keyword; <code>SYNC</code> is implicit).</li><li>Exposes three pseudo-fields: <ul><li><code>.addr</code> — address input, set via <code>&lt;=</code> in <code>SYNCHRONOUS</code> blocks</li><li><code>.data</code> — read data output (1 cycle latency), readable in any block</li><li><code>.wdata</code> — write data input, assigned via <code>&lt;=</code> in <code>SYNCHRONOUS</code> blocks</li></ul></li><li>If <code>.wdata</code> is not assigned in a given execution path, no write occurs (read-only cycle).</li><li><code>.addr</code> and <code>.wdata</code> may each be assigned at most once per execution path.</li><li><code>mem.port[addr]</code> indexing syntax is illegal on <code>INOUT</code> ports (must use <code>.addr</code>).</li><li>Write modes (<code>WRITE_FIRST</code>, <code>READ_FIRST</code>, <code>NO_CHANGE</code>) apply to <code>INOUT</code> ports.</li><li>Cannot be mixed with <code>IN</code> or <code>OUT</code> ports in the same MEM declaration.</li></ul><h2 id="write-modes" tabindex="-1">Write modes <a class="header-anchor" href="#write-modes" aria-label="Permalink to “Write modes”">​</a></h2><p>Write mode governs read-during-write behavior when a read and write target the same address in the same cycle.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Read returns</th><th>Default?</th></tr></thead><tbody><tr><td><code>WRITE_FIRST</code></td><td>Newly written data (post-write)</td><td>Yes</td></tr><tr><td><code>READ_FIRST</code></td><td>Old data (pre-write)</td><td>No</td></tr><tr><td><code>NO_CHANGE</code></td><td>Previous output value (unchanged)</td><td>No</td></tr></tbody></table><p>Syntax (shorthand or attribute form):</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>IN wr;                          // default WRITE_FIRST</span></span>
<span class="line"><span>IN wr WRITE_FIRST;</span></span>
<span class="line"><span>IN wr READ_FIRST;</span></span>
<span class="line"><span>IN wr NO_CHANGE;</span></span>
<span class="line"><span>IN wr { WRITE_MODE = READ_FIRST; };</span></span>
<span class="line"><span></span></span>
<span class="line"><span>INOUT rw;                       // default WRITE_FIRST</span></span>
<span class="line"><span>INOUT rw WRITE_FIRST;</span></span>
<span class="line"><span>INOUT rw READ_FIRST;</span></span>
<span class="line"><span>INOUT rw NO_CHANGE;</span></span>
<span class="line"><span>INOUT rw { WRITE_MODE = READ_FIRST; };</span></span></code></pre></div><p>When <code>addr_r != addr_w</code>, all modes behave identically (return stored word at addr_r).</p><p>For <code>INOUT</code> ports, write mode controls what <code>.data</code> shows when <code>.wdata</code> is assigned in the same cycle.</p><h2 id="initialization" tabindex="-1">Initialization <a class="header-anchor" href="#initialization" aria-label="Permalink to “Initialization”">​</a></h2><h3 id="literal-initialization" tabindex="-1">Literal initialization <a class="header-anchor" href="#literal-initialization" aria-label="Permalink to “Literal initialization”">​</a></h3><ul><li>All words initialized to the same literal value.</li><li>Init literal must not contain <code>x</code>.</li><li>Result width must be &lt;= word_width; overflow is a compile error.</li></ul><h3 id="file-based-initialization" tabindex="-1">File-based initialization <a class="header-anchor" href="#file-based-initialization" aria-label="Permalink to “File-based initialization”">​</a></h3><ul><li>Syntax: <code>= @file(&quot;path&quot;)</code>, <code>= @file(CONST_NAME)</code>, or <code>= @file(CONFIG.NAME)</code></li><li>The path argument may be a literal string, a module-local string CONST, or a project-level string CONFIG reference.</li><li>Using a numeric CONST/CONFIG where a string path is expected is a compile error.</li><li>File size must not exceed <code>depth * word_width</code> bits.</li><li>Smaller files are zero-padded; larger files produce a compile error.</li><li>Files must not contain undefined bits.</li><li>Supported formats: <code>.bin</code>, <code>.hex</code>, <code>.mif</code>, <code>.coe</code>, <code>.mem</code> (Verilog memory format with <code>0</code>/<code>1</code> and <code>//</code> comments). Tool-specific formats allowed.</li></ul><h2 id="access-rules-summary" tabindex="-1">Access rules summary <a class="header-anchor" href="#access-rules-summary" aria-label="Permalink to “Access rules summary”">​</a></h2><table tabindex="0"><thead><tr><th>Context</th><th>ASYNC OUT</th><th>SYNC OUT .addr</th><th>SYNC OUT .data</th><th>IN write</th><th>INOUT .addr</th><th>INOUT .data</th><th>INOUT .wdata</th></tr></thead><tbody><tr><td>ASYNCHRONOUS</td><td><code>mem.port[addr]</code> (read)</td><td>illegal</td><td>read OK</td><td>illegal</td><td>illegal</td><td>read OK</td><td>illegal</td></tr><tr><td>SYNCHRONOUS</td><td>illegal</td><td><code>&lt;= addr</code></td><td>read OK</td><td><code>mem.port[addr] &lt;= val</code></td><td><code>&lt;= addr</code></td><td>read OK</td><td><code>&lt;= val</code></td></tr></tbody></table><h2 id="scope-and-uniqueness" tabindex="-1">Scope and uniqueness <a class="header-anchor" href="#scope-and-uniqueness" aria-label="Permalink to “Scope and uniqueness”">​</a></h2><ul><li>Memory names must be unique within the module.</li><li>Port names must be unique within the MEM block and must not conflict with module-level identifiers.</li></ul><h2 id="chip-specific-validation" tabindex="-1">Chip-specific validation <a class="header-anchor" href="#chip-specific-validation" aria-label="Permalink to “Chip-specific validation”">​</a></h2><p>When the project <code>CHIP</code> is not &quot;GENERIC&quot; and chip data is available, the compiler validates MEM width, depth, and port counts against the chip&#39;s supported memory configurations. If <code>CHIP</code> is &quot;GENERIC&quot;, no chip-specific validation is performed.</p><h2 id="mem-vs-register-vs-wire" tabindex="-1">MEM vs REGISTER vs WIRE <a class="header-anchor" href="#mem-vs-register-vs-wire" aria-label="Permalink to “MEM vs REGISTER vs WIRE”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>REGISTER</th><th>WIRE</th><th>MEM</th></tr></thead><tbody><tr><td>Storage</td><td>Single value (N bits)</td><td>None (combinational)</td><td>Array (word_width x depth)</td></tr><tr><td>Read timing</td><td>Combinational (current value)</td><td>Combinational</td><td>Async or sync</td></tr><tr><td>Write timing</td><td>Clock-synchronized</td><td>Continuous assignment</td><td>Clock-synchronized</td></tr><tr><td>Port count</td><td>1 (implicit)</td><td>N/A</td><td>Multiple explicit</td></tr><tr><td>Access syntax</td><td><code>reg_name</code></td><td><code>wire_name</code></td><td>ASYNC: <code>mem.port[addr]</code>, SYNC/INOUT: <code>.addr</code>/<code>.data</code>/<code>.wdata</code></td></tr><tr><td>Initialization</td><td>Literal only</td><td>N/A</td><td>Literal or file</td></tr></tbody></table><h2 id="inout-examples" tabindex="-1">INOUT Examples <a class="header-anchor" href="#inout-examples" aria-label="Permalink to “INOUT Examples”">​</a></h2><h3 id="single-port-memory-inout" tabindex="-1">Single Port Memory (INOUT) <a class="header-anchor" href="#single-port-memory-inout" aria-label="Permalink to “Single Port Memory (INOUT)”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>MEM(TYPE=BLOCK) {</span></span>
<span class="line"><span>  mem [16] [256] = 16&#39;h0000 {</span></span>
<span class="line"><span>    INOUT rw;</span></span>
<span class="line"><span>  };</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SYNCHRONOUS(CLK=clk) {</span></span>
<span class="line"><span>  mem.rw.addr &lt;= addr;</span></span>
<span class="line"><span>  rd_data &lt;= mem.rw.data;</span></span>
<span class="line"><span>  IF (wr_en) {</span></span>
<span class="line"><span>    mem.rw.wdata &lt;= wr_data;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>Single <code>INOUT</code> port → Single Port BSRAM mode</li><li>Shared address for read and write</li><li>Synchronous read (1 cycle latency)</li><li>Write gated by condition</li></ul><h3 id="true-dual-port-memory-2×-inout" tabindex="-1">True Dual Port Memory (2× INOUT) <a class="header-anchor" href="#true-dual-port-memory-2×-inout" aria-label="Permalink to “True Dual Port Memory (2× INOUT)”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>MEM(TYPE=BLOCK) {</span></span>
<span class="line"><span>  mem [16] [256] = 16&#39;h0000 {</span></span>
<span class="line"><span>    INOUT port_a;</span></span>
<span class="line"><span>    INOUT port_b;</span></span>
<span class="line"><span>  };</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SYNCHRONOUS(CLK=clk) {</span></span>
<span class="line"><span>  mem.port_a.addr &lt;= addr_a;</span></span>
<span class="line"><span>  rd_data_a &lt;= mem.port_a.data;</span></span>
<span class="line"><span>  IF (wr_en_a) {</span></span>
<span class="line"><span>    mem.port_a.wdata &lt;= wr_data_a;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  mem.port_b.addr &lt;= addr_b;</span></span>
<span class="line"><span>  rd_data_b &lt;= mem.port_b.data;</span></span>
<span class="line"><span>  IF (wr_en_b) {</span></span>
<span class="line"><span>    mem.port_b.wdata &lt;= wr_data_b;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>Two <code>INOUT</code> ports → Dual Port BSRAM mode</li><li>Each port has independent address, read data, and write data</li><li>Both ports can read and write independently in the same cycle</li><li><strong>Note:</strong> Write behavior when both ports write to the same address in the same cycle is undefined (hardware-dependent)</li></ul>`,45)])])}const u=a(d,[["render",i]]);export{m as __pageData,u as default};
